            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "Archivist Threnn",
                text = "*(A precise woman in a counting-house surrounded by ledgers, who covers a page as you enter the way a gambler covers a hand.)* Whatever you've heard, the *official* harvest-toll is four hundred and twelve souls, district-wide, year to date, and that is the figure the property assessments are based on, and that is the figure that *stays.* *(she folds her hands over the hidden page.)* You're the Returned. You'll have seen more bodies than my ledger admits. I'd ask you, as a *professional* courtesy, to keep that arithmetic to yourself. The Upper City's land values rest on a comfortable number, and a great many *innocent* fortunes would crater if the *true* one got about.",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.threnn_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Archivist Threnn",
                text = "*(She taps the covered page.)* You think me ghoulish. I'm an *archivist.* I record what is, and what *is*, Returned, is that a city which admits its true death-toll is a city whose patriars flee, whose rents collapse, whose *remaining* living lose the homes they have left. *(coldly reasonable.)* So I keep two ledgers. The *true* one — *(she touches it, and her composure flickers)* — and the *survivable* one. And I tell myself the lie keeps the living housed, which is *also* a mercy, of a colder kind. *(she meets your eyes.)* Tell me I'm wrong. Tell me the truth doesn't crater a fortune that shelters real families. Tell me an honest number wouldn't kill more of the living than my lie ever buried.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 17] \"The true ledger isn't for property values. It's the only honest grave any of these people will ever get. You keep it because *someone* has to count them right — even if you can't say so.\"", nextNodeId = "truegrave", checkAbility = Ability.Wisdom, checkDC = 17, failNodeId = "defend" },
                    new DialogueChoice { text = "\"Show me the true ledger. The dead deserve an accurate count more than the patriars deserve cheap rent.\"", nextNodeId = "truecount", effects = new[] { new FlagClause { key = "sq.threnn_true_ledger", op = FlagOp.SetTrue } } },
                    new DialogueChoice { text = "\"Both can be true, Threnn. Keep the lie public — but give the true count to Lula's list, where the names can rest right.\"", nextNodeId = "lula", conditions = new[] { new FlagClause { key = "sq.lulaslist_active", op = FlagOp.RequireBoolTrue } } },
                    new DialogueChoice { text = "\"You've made forgetting into bookkeeping. That's the most respectable evil in this whole city.\"", nextNodeId = "evil", effects = new[] { new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = -1 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "truegrave", speaker = "Archivist Threnn",
                text = "*(Her hand stills on the covered page, and when she speaks the precision has gone soft.)* ...The only honest grave. *(quietly.)* You've seen it, then. What I couldn't say even to myself. *(she uncovers the page — column after column of names, in a hand far more careful than any property ledger requires.)* I tell the world it's for the assessments. The truth is I cannot *bear* for them to be a round number. Four hundred and twelve is a *figure.* But here — *(she touches a name)* — here is Hessel, who mended nets, and here is Asa, who sold winkles, and I have written each one *correctly*, in full, because if I am the only person in this city keeping the *true* count, then I am the only person treating them as *subtractions from something that mattered* rather than *adjustments to a land value.* *(she swallows.)* I am a coward who hides it behind arithmetic. But the arithmetic is *true*, Returned. It's the truest thing in the Upper City. And no one was ever meant to see it but the dead.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.threnn_true_ledger_revealed", op = FlagOp.SetTrue }, new FlagClause { key = "sq.threnn_true_ledger", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "truecount", speaker = "Archivist Threnn",
                text = "*(She hesitates, the archivist warring with the accountant.)* The true count. *(slowly, she slides the page toward you.)* Take it. *(quietly.)* I have wanted, for a year, to be *forced* to surrender it — so that the cratering of fortunes would be *your* doing, not mine, and I could keep my comfortable lie and my comfortable conscience both. *(she stops you, hand on yours.)* But understand what you carry. This page, made public, *will* collapse rents, *will* drive patriars to flee, *will* make some of the living homeless to honor the dead. *(she lets go.)* I've kept the lie because I couldn't choose. You can. So choose with your eyes open, Returned — the dead's true grave, or the living's cheap shelter. I never found the courage to pick. Gods help you if you do.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.threnn_surrenders_ledger", op = FlagOp.SetTrue }, new FlagClause { key = "sq.threnn_true_ledger", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "lula", speaker = "Archivist Threnn",
                text = "*(She blinks, the accountant genuinely startled by an *elegant* solution.)* Both ledgers. *(slowly.)* The lie stays public — the rents hold, the living keep their homes — but the *true* count goes to the child's list, where it's a *memorial*, not an *assessment.* *(a long pause.)* That's... that's the first proposal I've heard that doesn't make me choose between the dead and the living. *(she copies the page with swift, practiced strokes — an archivist's true gift.)* The girl gets the names, exact and whole. The patriars keep their comfortable number. And I — *(her voice catches)* — I get to stop being the only one who knows the truth, which is a loneliness I'd not wish on a tax collector. Take it to her. Tell her an archivist says: *count them right, where it can't crater anything but the silence.* That, I can finally afford.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.threnn_gives_to_lula", op = FlagOp.SetTrue }, new FlagClause { key = "sq.threnn_true_ledger", op = FlagOp.SetTrue }, new FlagClause { key = "sq.lulaslist_active", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "evil", speaker = "Archivist Threnn",
                text = "*(She receives it without flinching, an accountant tallying a debt.)* The most respectable evil in the city. *(quietly.)* Yes. I've thought so myself, at the bottom of the true ledger, where no assessment goes. *(she covers the page again.)* But respectable evil keeps the living housed, Returned, and dramatic virtue would put grieving widows on the street to honor the grieving dead, and I have never been able to weigh one grief against the other and call it *solved.* *(coldly.)* You judge the bookkeeping. Fine. But before you do — find me the moral arithmetic that saves *both* the dead's honor and the living's roof, and I will adopt it gladly. I've been looking for it for a year. The ledger's the best I could manage. It's not enough. I *know* it's not enough. Knowing isn't the same as having a better column to write in.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.threnn_judged", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "defend", speaker = "Archivist Threnn",
                text = "*(The precision snaps back into place.)* A sentimental theory. *(coolly.)* The ledger is for the assessments, nothing more. I am an archivist; I do not *grieve* in columns. *(but her hand has not left the covered page.)* Good day, Returned. The figure is four hundred and twelve. It will remain four hundred and twelve. Some numbers are load-bearing, whatever lies beneath them.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Archivist Threnn",
                text = "*(She returns to her two ledgers — the survivable lie and the unbearable truth — and you carry away the understanding that even here, in the coldest counting-house in the Upper City, *someone* could not stop herself from writing the names of the forgotten down correctly, where only the dead would ever read them.)*",
            });

