            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "Old Marrow",
                text = "*(Propped against a headstone in Grud's graveyard, grey and unmistakably deceased, a corpse rattles a dice cup with surprising dexterity.)* Grud not about? Good. *(the dead jaw works; the voice is dry as turned earth.)* Then I'll deal you in before the big lummox 'plants' me again. *(he is, you note, entirely a corpse, and entirely animate, and entirely cheating — you can see the loaded die from here.)* Name's Marrow. Been dead, oh, three months now. Grud keeps burying me; I keep coming up for the morning game. He thinks I don't notice the dirt. I think he doesn't notice I *win.* We're both being polite. It's the foundation of every good friendship — mutual, courteous denial.",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.marrow_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Old Marrow",
                text = "*(He rattles the cup; the loaded die clicks.)* Now you're wondering — and don't deny it, the living always wonder — *why* a dead man's still rattling about a graveyard cheating at dice instead of off to his rest. *(he chuckles, a sound like gravel.)* Simple. I *owe* Grud thirty years of dice debts, see, from when we were both breathing, and a Tendir does *not* skip out on a debt by the cheap expedient of *dying.* *(he sets down the cup.)* So I stay. I lose on purpose at first — let him win back a copper here, a copper there — and then I cheat to even it, so we end each morning square, and neither of us ever has to say goodbye. *(quietly, for a corpse.)* That's the secret nobody tells you about the dead, friend. Some of us don't linger out of *unfinished business.* We linger out of *unfinished friendship.* The business I'd happily leave owing.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 14] \"You're not paying off a debt. You're staying because Grud buried his whole family, and you're the one friend the harvest can't take from him — because you're already gone.\"", nextNodeId = "friend", checkAbility = Ability.Wisdom, checkDC = 14, failNodeId = "deny" },
                    new DialogueChoice { text = "\"Does Grud know you cheat? Does he know you *know* he knows you're dead?\"", nextNodeId = "know" },
                    new DialogueChoice { text = "\"Loaded die, third from the left. Rest, Marrow. The debt's paid — you stayed three months past dying to square it.\"", nextNodeId = "rest" },
                    new DialogueChoice { text = "\"Deal me in, then. A dead man's game sounds like the only honest table left.\"", nextNodeId = "deal", effects = new[] { new FlagClause { key = "companion.varra.approval", op = FlagOp.AddInt, amount = 2 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "friend", speaker = "Old Marrow",
                text = "*(The dice cup goes still in his grey hands. For a long moment the corpse just regards you.)* ...Well. *(quietly, the gravel softening.)* Aren't you the sharp one. *(he sets the cup down.)* Aye. The harvest took his whole family in the bad winter — eight of them, all at once, and Grud planted every one with a joke on his lips and his heart in pieces. *(the dead eyes are, impossibly, wet.)* And I thought: the harvest can take the *living* from that big daft fellow, but it can't take *me* — I'm already *gone*, see, already filed, nothing left for the nothing to *want.* *(he chuckles, wet.)* So I'm the one friend that can't be harvested out from under him. I stay to lose at dice of a morning so he's got *one* face that turns up every day, reliable as the dirt. *(quietly.)* Don't tell him I said so. He thinks it's the debt. Let him think it's the debt. A man who's buried eight can't bear to know he's being *pitied* by a corpse. Let it be dice. Dice he can stand.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.marrow_truth", op = FlagOp.SetTrue }, new FlagClause { key = "npc.grud_has_marrow", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "know", speaker = "Old Marrow",
                text = "*(He wheezes a laugh.)* Does Grud *know.* *(he shakes his grey head, fond.)* 'Course he knows. He's a gravedigger, friend, not a fool — he knows a corpse when he plants one, and he's planted *me* a dozen times. *(he taps his temple, where the skin's gone to parchment.)* And I know he knows. And he knows I know he knows. *(he picks up the cup.)* But the *morning* he *says* it — the morning one of us admits I'm a dead man cheating a grieving friend at dice — that's the morning it has to *stop*, see. That's the morning I rest and he's alone again. *(quietly.)* So we don't say it. We just play. Some kindnesses can only survive in the *unsaid*, friend. Name them out loud and they die of the exposure. Now — you playing, or philosophizing? With me it's hard to do both; I've only the one expression left.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.marrow_the_unsaid", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "rest", speaker = "Old Marrow",
                text = "*(He goes very still. The loaded die rolls from his slackening grey fingers and comes up, for once, an honest number.)* ...You'd send me off. *(quietly, without rancor.)* Aye. The debt's paid. Three months of squaring it, copper by copper. I *could* rest. *(he looks toward the graveyard gate, where the morning light is coming up gold.)* But here's the thing you've not weighed, sharp as you are: if I rest, Grud's alone of a morning. The harvest took his eight, and I'm the ninth face, the only one left that turns up reliable. *(he picks the honest die back up, and palms the loaded one again, deliberate.)* So no. Not yet. The debt's an excuse and we both know it. I'll stay till *Grud's* ready to lose his last friend — and that big daft grieving man is not ready, not near. *(he rattles the cup.)* Rest can wait. Friendship's the longer debt. Deal you in?",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.marrow_stays_for_grud", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "deal", speaker = "Old Marrow",
                text = "*(He brightens, insofar as a corpse can.)* HA! A *living* one, sitting down to a dead man's game! *(he deals with grey, dextrous fingers.)* Now *this* is a morning. *(he leans in, conspiratorial.)* Fair warning, friend — I cheat. Shamelessly. It's the one vice the grave didn't cure. But I cheat *gentle*, just enough to keep things even, never enough to *win* — winning's rude, and besides, a corpse with money's got nowhere to spend it. *(he rolls; the loaded die obeys.)* See? Even. Always even. *(quietly, between rolls.)* That's the trick to staying, living or dead. Never get *ahead.* Get ahead and the game ends. Stay *even*, and it goes on forever, and forever's all a dead man's got to offer a grieving friend. Your roll.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "deny", speaker = "Old Marrow",
                text = "*(He waves a grey hand, dismissive, the dice rattling.)* Pity from the living. Spare me. *(but the cup stills, just for a moment.)* It's the *debt*, friend, thirty years of dice debts, plain as the dirt under my nails. Nothing sentimental. *(he won't look at the graveyard gate.)* Now deal or shove off. The big fellow'll be back from his rounds soon, and he likes to think he's surprising me.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Old Marrow",
                text = "*(He rattles the cup against the morning, a dead man cheating gently at the one honest table left, staying square with a grieving friend one copper at a time — and as you go, you hear Grud's cheerful boom approaching, and Marrow calls out \"About time, you lummox, I've gone and *died* waiting,\" and the two of them laugh, the living and the dead, at the oldest joke either of them has.)*",
            });

            NpcGateMarrowDialogue = g;
        }
    }
}
